class Solution {
public:
    int maximumLength(string s) {
        int n = s.size();
        int res = -1;
        for (int len = 1; len <= n; len++) {
            for (int i = 0; i <= n - len; i++) {
                string substr = s.substr(i, len);
                if (std::set<char>(substr.begin(), substr.end()).size() == 1) {
                    int count = 0;
                    for (int j = 0; j <= n - len; j++) {
                        if (s.substr(j, len) == substr) {
                            count++;
                        }
                    }
                    if (count >= 3 && len > res) {
                        res = len;
                    }
                }
            }
        }
        return res;
    }
};
